// Overlap AND how deep, to push out of a solid.
Rect mover, solid;
s16 overlapX, overlapY;
rectInit(&mover, 120, 100, 16, 16);   // the thing that moves
rectInit(&solid, 128, 112, 32, 8);    // a wall / platform tile
if (collideRectEx(&mover, &solid, &overlapX, &overlapY)) {
    // classic AABB response: resolve along the smaller penetration
    if (overlapX < overlapY) { mover.x -= overlapX; }
    else                     { mover.y -= overlapY; }
}

